class Solution:
    def maxTurbulenceSize(self, arr):
        # Independent approach: build the sign sequence of adjacent steps,
        # then find the longest run where consecutive signs strictly alternate
        # and neither sign is zero (equal neighbours).
        n = len(arr)
        if n == 1:
            return 1
        signs = []
        for i in range(1, n):
            if arr[i] > arr[i - 1]:
                signs.append(1)
            elif arr[i] < arr[i - 1]:
                signs.append(-1)
            else:
                signs.append(0)
        best_steps = 0
        cur = 0
        for i in range(len(signs)):
            if signs[i] == 0:
                cur = 0
            elif i > 0 and signs[i] == -signs[i - 1]:
                cur += 1
            else:
                cur = 1
            best_steps = max(best_steps, cur)
        return best_steps + 1

solutions.python:
class Solution:
    def maxTurbulenceSize(self, arr):
        n = len(arr)
        best = 1
        up = down = 1
        for i in range(1, n):
            if arr[i] > arr[i - 1]:
                up = down + 1
                down = 1
            elif arr[i] < arr[i - 1]:
                down = up + 1
                up = 1
            else:
                up = down = 1
            best = max(best, up, down)
        return best

